/**
 * @summary Send message to AI health chatbot
 */
export const getChatUrl = () => {
  return `/api/chat`;
};

export const chat = async (
  chatMessage: ChatMessage,
  options?: RequestInit,
): Promise<ChatResponse> => {
  return customFetch<ChatResponse>(getChatUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(chatMessage),
  });
};

export const getChatMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof chat>>,
    TError,
    { data: BodyType<ChatMessage> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof chat>>,
  TError,
  { data: BodyType<ChatMessage> },
  TContext
> => {
  const mutationKey = ["chat"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof chat>>,
    { data: BodyType<ChatMessage> }
  > = (props) => {
    const { data } = props ?? {};

    return chat(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ChatMutationResult = NonNullable<Awaited<ReturnType<typeof chat>>>;
export type ChatMutationBody = BodyType<ChatMessage>;
export type ChatMutationError = ErrorType<unknown>;

/**
 * @summary Send message to AI health chatbot
 */
export const useChat = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof chat>>,
    TError,
    { data: BodyType<ChatMessage> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof chat>>,
  TError,
  { data: BodyType<ChatMessage> },
  TContext
> => {
  return useMutation(getChatMutationOptions(options));
};
